You are working in the directory /tmp/sv-3993fbc230314d819643313ae54f5003/ShipmentTracker. This is a Blazor Web App with Auto interactivity mode (Server + WebAssembly) and Individual accounts authentication, using .NET 11 preview. The solution has two projects: `ShipmentTracker` (server) and `ShipmentTracker.Client` (WASM client).

Build a shipment tracking system for a logistics company. Here's what to implement:

## 1. Shared Model (in Client project so both projects can use it)

Create file `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public double WeightKg { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Exception
}
```

## 2. Update ApplicationUser (server Data/ApplicationUser.cs)

Add a Role property:
```csharp
using Microsoft.AspNetCore.Identity;

namespace ShipmentTracker.Data;

public class ApplicationUser : IdentityUser
{
    public string Role { get; set; } = "Customer";
}
```

## 3. Update ApplicationDbContext (server Data/ApplicationDbContext.cs)

Add a DbSet for Shipments:
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();
}
```

## 4. Create Shipment API Endpoints (server)

Create file `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers get all, customers get their own)
        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser is null) return Results.Unauthorized();

            if (appUser.Role == "Dispatcher")
            {
                var shipments = await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
                return Results.Ok(shipments);
            }
            else
            {
                var shipments = await db.Shipments
                    .Where(s => s.CustomerEmail == appUser.Email)
                    .OrderByDescending(s => s.ShippedDate)
                    .ToListAsync();
                return Results.Ok(shipments);
            }
        });

        // Get shipment by tracking number (public tracking)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (Shipment shipment, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            shipment.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id}", async (int id, Shipment updated, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = updated.Status;
            shipment.Destination = updated.Destination;
            shipment.EstimatedDelivery = updated.EstimatedDelivery;
            shipment.Description = updated.Description;
            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });

        // Delete shipment (dispatchers only)
        group.MapDelete("/{id}", async (int id, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }
}
```

## 5. Create Seed Data (server)

Create file `ShipmentTracker/Data/SeedData.cs`:
```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider serviceProvider)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();

        await db.Database.MigrateAsync();

        // Seed dispatcher
        if (await userManager.FindByEmailAsync("dispatcher@logistics.com") is null)
        {
            var dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@logistics.com",
                Email = "dispatcher@logistics.com",
                EmailConfirmed = true,
                Role = "Dispatcher"
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
        }

        // Seed customer
        if (await userManager.FindByEmailAsync("customer@example.com") is null)
        {
            var customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true,
                Role = "Customer"
            };
            await userManager.CreateAsync(customer, "Customer1!");
        }

        // Seed shipments
        if (!await db.Shipments.AnyAsync())
        {
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "SHP-20260101-1001",
                    Origin = "New York, USA",
                    Destination = "London, UK",
                    Status = ShipmentStatus.InTransit,
                    ShippedDate = DateTime.UtcNow.AddDays(-3),
                    EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                    CustomerEmail = "customer@example.com",
                    Description = "Electronics - Laptop",
                    WeightKg = 2.5
                },
                new Shipment
                {
                    TrackingNumber = "SHP-20260102-1002",
