```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<Shipment>> GetShipmentsAsync()
    {
        var result = await http.GetFromJsonAsync<List<Shipment>>("/api/shipments");
        return result ?? [];
    }

    public async Task<Shipment?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment?> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", shipment);
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<bool> UpdateShipmentAsync(Shipment shipment)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{shipment.Id}", shipment);
        return response.IsSuccessStatusCode;
    }

    public async Task<bool> DeleteShipmentAsync(int id)
    {
        var response = await http.DeleteAsync($"/api/shipments/{id}");
        return response.IsSuccessStatusCode;
    }
}
```

