## 4. Create Shipment API Endpoints (server)

Create file `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using System.Security.Claims;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers get all, customers get their own)
        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser is null) return Results.Unauthorized();

            if (appUser.Role == "Dispatcher")
            {
                var shipments = await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
                return Results.Ok(shipments);
            }
            else
            {
                var shipments = await db.Shipments
                    .Where(s => s.CustomerEmail == appUser.Email)
                    .OrderByDescending(s => s.ShippedDate)
                    .ToListAsync();
                return Results.Ok(shipments);
            }
        });

        // Get shipment by tracking number (public tracking)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (Shipment shipment, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            shipment.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id}", async (int id, Shipment updated, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = updated.Status;
            shipment.Destination = updated.Destination;
            shipment.EstimatedDelivery = updated.EstimatedDelivery;
            shipment.Description = updated.Description;
            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });

        // Delete shipment (dispatchers only)
        group.MapDelete("/{id}", async (int id, ApplicationDbContext db, ClaimsPrincipal user, UserManager<ApplicationUser> userManager) =>
        {
            var appUser = await userManager.GetUserAsync(user);
            if (appUser?.Role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }
}
```

