Create file `ShipmentTracker.Client/Pages/Dispatch.razor`:
```razor
@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject ShipmentService ShipmentSvc
@rendermode InteractiveAuto

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>📦 Dispatch Dashboard</h1>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input @bind="newShipment.Origin" class="form-control" placeholder="City, Country" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input @bind="newShipment.Destination" class="form-control" placeholder="City, Country" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Customer Email</label>
                    <input @bind="newShipment.CustomerEmail" class="form-control" type="email" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input @bind="newShipment.Description" class="form-control" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Weight (kg)</label>
                    <input @bind="newShipment.WeightKg" class="form-control" type="number" step="0.1" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Est. Delivery</label>
                    <input @bind="newShipment.EstimatedDelivery" class="form-control" type="date" />
                </div>
                <div class="col-12">
                    <button class="btn btn-success me-2" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <label class="me-2">Filter by status:</label>
        <select @bind="statusFilter" class="form-select d-inline-block" style="width: auto;">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <button class="btn btn-primary" @onclick="() => showCreateForm = !showCreateForm">
        ➕ New Shipment
    </button>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.CustomerEmail</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select @bind="s.Status" @bind:after="() => UpdateStatus(s)" class="form-select form-select-sm" style="width:auto; display:inline-block;">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                            <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeleteShipment(s.Id)">🗑️</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private Shipment newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
    private bool showCreateForm;
    private string statusFilter = "";

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(statusFilter)
            ? shipments ?? []
            : (shipments ?? []).Where(s => s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentSvc.GetShipmentsAsync();
    }

    private async Task CreateShipment()
    {
        newShipment.ShippedDate = DateTime.UtcNow;
        var created = await ShipmentSvc.CreateShipmentAsync(newShipment);
        if (created is not null)
        {
            shipments?.Insert(0, created);
            newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
            showCreateForm = false;
        }
    }

    private async Task UpdateStatus(Shipment shipment)
    {
        await ShipmentSvc.UpdateShipmentAsync(shipment);
    }

    private async Task DeleteShipment(int id)
    {
        if (await ShipmentSvc.DeleteShipmentAsync(id))
        {
            shipments?.RemoveAll(s => s.Id == id);
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}
```

## 11. Customer Tracking Page (Client project)

Create file `ShipmentTracker.Client/Pages/Track.razor`:
```razor
@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject ShipmentService ShipmentSvc
@rendermode InteractiveAuto

<PageTitle>Track Shipments</PageTitle>

<h1>📍 My Shipments</h1>

<div class="mb-4">
    <div class="input-group" style="max-width: 500px;">
        <input @bind="searchTracking" @bind:event="oninput" class="form-control" placeholder="Enter tracking number to search..." />
        <button class="btn btn-outline-primary" @onclick="SearchByTracking">🔍 Track</button>
    </div>
</div>

@if (trackedShipment is not null)
{
    <div class="card mb-4 border-primary">
        <div class="card-header bg-primary text-white">
            <strong>Tracking Result: @trackedShipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @trackedShipment.Origin</p>
                    <p><strong>To:</strong> @trackedShipment.Destination</p>
                    <p><strong>Description:</strong> @trackedShipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span></p>
                    <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                </div>
            </div>
            @{
                var progress = GetProgressPercent(trackedShipment.Status);
            }
            <div class="progress mt-3" style="height: 25px;">
                <div class="progress-bar bg-success" style="width: @progress%">@trackedShipment.Status</div>
            </div>
        </div>
    </div>
}
else if (searchPerformed)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}

<h3 class="mt-4">My Shipments</h3>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>You have no shipments.</p>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h6 class="card-title">@s.TrackingNumber</h6>
                        <p class="card-text mb-1"><small class="text-muted">@s.Description</small></p>
                        <p class="card-text mb-1">📍 @s.Origin → @s.Destination</p>
                        <p class="card-text mb-1">
                            <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                        </p>
                        <p class="card-text"><small>🚚 Est. Delivery: <strong>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</strong></small></p>
                        @{
                            var prog = GetProgressPercent(s.Status);
                        }
                        <div class="progress" style="height: 8px;">
                            <div class="progress-bar bg-success" style="width: @prog%"></div>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Shipment>? shipments;
    private Shipment? trackedShipment;
    private string searchTracking = "";
    private bool searchPerformed;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentSvc.GetShipmentsAsync();
    }

    private async Task SearchByTracking()
    {
        searchPerformed = true;
        trackedShipment = null;
        if (!string.IsNullOrWhiteSpace(searchTracking))
        {
            trackedShipment = await ShipmentSvc.TrackShipmentAsync(searchTracking.Trim());
        }
    }

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}
```

